import React, { useState } from "react";

/* ------------------------------------------------------------------ */
/* Styles                                                               */
/* ------------------------------------------------------------------ */

const styles = `

`;

/* ------------------------------------------------------------------ */
/* Main component                                                       */
/* ------------------------------------------------------------------ */

const SECTORS = ["Domestic", "Commercial", "Both"];

export default function BasicDetails() {
  const [schemeName, setSchemeName] = useState("");
  const [category, setCategory] = useState("solar");
  const [subcategory, setSubcategory] = useState("grid_rooftop");
  const [measuringUnit, setMeasuringUnit] = useState("kW");
  const [technology, setTechnology] = useState("Solar PV");
  const [schemeType, setSchemeType] = useState("subsidy");
  const [status, setStatus] = useState("active");
  const [startDate, setStartDate] = useState("2025-04-01");
  const [endDate, setEndDate] = useState("2030-03-31");
  const [sector, setSector] = useState("Both");
  const [description, setDescription] = useState("");
  const [brochure, setBrochure] = useState(null);
  const [image, setImage] = useState(null);
  const [terms, setTerms] = useState("");

  return (
    <div className="basic-details-wrapper">
      <style>{styles}</style>

      <div className="basic-details-card">
        <div className="basic-details-topbar"></div>
        <div className="basic-details-body">
          <div className="basic-details-header">
            <div className="basic-details-icon">☀</div>
            <div>
              <h5>Basic Details</h5>
              <small>Identify the scheme</small>
            </div>
          </div>

          <div className="field-group">
            <span className="form-label-sm">SCHEME NAME</span>
            <input
              type="text"
              className="form-control-custom"
              placeholder="e.g. PM Surya Ghar Muft Bijli Yojana"
              value={schemeName}
              onChange={(e) => setSchemeName(e.target.value)}
            />
          </div>

          <div className="field-grid">
            <div className="field-group">
              <span className="form-label-sm">CATEGORY</span>
              <select
                className="form-control-custom"
                value={category}
                onChange={(e) => setCategory(e.target.value)}
              >
                <option value="solar">Solar</option>
                <option value="wind">Wind</option>
                <option value="hybrid">Hybrid</option>
              </select>
            </div>
            <div className="field-group">
              <span className="form-label-sm">SUBCATEGORY</span>
              <select
                className="form-control-custom"
                value={subcategory}
                onChange={(e) => setSubcategory(e.target.value)}
              >
                <option value="grid_rooftop">Grid Connected Rooftop Solar</option>
                <option value="off_grid">Off Grid Solar</option>
                <option value="ground_mounted">Ground Mounted Solar</option>
              </select>
            </div>

            <div className="field-group">
              <span className="form-label-sm">MEASURING UNIT</span>
              <input
                type="text"
                className="form-control-custom"
                value={measuringUnit}
                onChange={(e) => setMeasuringUnit(e.target.value)}
              />
            </div>
            <div className="field-group">
              <span className="form-label-sm">TECHNOLOGY</span>
              <input
                type="text"
                className="form-control-custom"
                value={technology}
                onChange={(e) => setTechnology(e.target.value)}
              />
            </div>

            <div className="field-group">
              <span className="form-label-sm">SCHEME TYPE</span>
              <select
                className="form-control-custom"
                value={schemeType}
                onChange={(e) => setSchemeType(e.target.value)}
              >
                <option value="subsidy">Subsidy</option>
                <option value="loan">Loan</option>
                <option value="rebate">Rebate</option>
              </select>
            </div>
            <div className="field-group">
              <span className="form-label-sm">STATUS</span>
              <select
                className="form-control-custom"
                value={status}
                onChange={(e) => setStatus(e.target.value)}
              >
                <option value="active">Active</option>
                <option value="inactive">Inactive</option>
                <option value="draft">Draft</option>
              </select>
            </div>

            <div className="field-group">
              <span className="form-label-sm">START DATE</span>
              <input
                type="date"
                className="form-control-custom"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
              />
            </div>
            <div className="field-group">
              <span className="form-label-sm">END DATE</span>
              <input
                type="date"
                className="form-control-custom"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
              />
            </div>
          </div>

          <div className="field-group">
            <span className="form-label-sm">SECTOR</span>
            <div className="pill-group">
              {SECTORS.map((s) => (
                <button
                  key={s}
                  type="button"
                  className={`pill ${sector === s ? "active" : ""}`}
                  onClick={() => setSector(s)}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          <div className="field-group">
            <span className="form-label-sm">DESCRIPTION</span>
            <textarea
              className="form-control-custom"
              placeholder="Brief about the scheme..."
              rows={3}
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>

          <div className="field-grid">
            <div className="field-group">
              <span className="form-label-sm">BROCHURE (PDF)</span>
              <input
                type="file"
                accept="application/pdf"
                className="form-control-custom"
                onChange={(e) => setBrochure(e.target.files?.[0] || null)}
              />
            </div>
            <div className="field-group">
              <span className="form-label-sm">IMAGE</span>
              <input
                type="file"
                accept="image/*"
                className="form-control-custom"
                onChange={(e) => setImage(e.target.files?.[0] || null)}
              />
            </div>
          </div>

          <div className="field-group" style={{ marginBottom: 0 }}>
            <span className="form-label-sm">TERMS &amp; CONDITIONS</span>
            <textarea
              className="form-control-custom"
              placeholder="Enter terms..."
              rows={3}
              value={terms}
              onChange={(e) => setTerms(e.target.value)}
            />
          </div>
        </div>
      </div>
    </div>
  );
}
